@ARTICLE{10.1016/j.jnutbio.2021.108623,
	author = {Vazhappilly CG and Amararathna M and Cyril AC and Linger R and Matar R and Merheb M and Ramadan WS and Radhakrishnan R and Rupasinghe HPV},
	title = {Current methodologies to refine bioavailability, delivery, and therapeutic efficacy of plant flavonoids in cancer treatment.},
	journal = {J Nutr Biochem},
	year = {2021},
	abstract = {Over the last two decades, several advancements have been made to improve the therapeutic efficacy of plant flavonoids, especially in cancer treatment. Factors such as low bioavailability, poor flavonoid stability and solubility, ineffective targeted delivery, and chemo-resistance hinder the application of flavonoids in anti-cancer therapy. Many anti-cancer compounds failed in the clinical trials because of unexpected altered clearance of flavonoids, poor absorption after administration, low efficacy, and/or adverse effects. Hence, the current research strategies are focused on improving the therapeutic efficacy of plant flavonoids, especially by enhancing their bioavailability through combination therapy, engineering gut microbiota, regulating flavonoids interaction with adenosine triphosphate binding cassette efflux transporters, and efficient delivery using nanocrystal and encapsulation technologies. This review aims to discuss different methodologies with examples from reported dietary flavonoids that showed an enhanced anti-cancer efficacy in both in vitro and in vivo models. Further, the review discusses the recent progress in biochemical modifications of flavonoids to improve bioavailability, solubility, and therapeutic efficacy.},
	doi = {10.1016/j.jnutbio.2021.108623},
	pmid = {33705948 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2020.615240,
	author = {Cuzzubbo S and Mangsbo S and Nagarajan D and Habra K and Pockley AG and McArdle SEB},
	title = {Cancer Vaccines: Adjuvant Potency, Importance of Age, Lifestyle, and Treatments.},
	journal = {Front Immunol},
	year = {2021},
	abstract = {Although the discovery and characterization of multiple tumor antigens have sparked the development of many antigen/derived cancer vaccines, many are poorly immunogenic and thus, lack clinical efficacy. Adjuvants are therefore incorporated into vaccine formulations to trigger strong and long-lasting immune responses. Adjuvants have generally been classified into two categories: those that 'depot' antigens (e.g. mineral salts such as aluminum hydroxide, emulsions, liposomes) and those that act as immunostimulants (Toll Like Receptor agonists, saponins, cytokines). In addition, several novel technologies using vector-based delivery of antigens have been used. Unfortunately, the immune system declines with age, a phenomenon known as immunosenescence, and this is characterized by functional changes in both innate and adaptive cellular immunity systems as well as in lymph node architecture. While many of the immune functions decline over time, others paradoxically increase. Indeed, aging is known to be associated with a low level of chronic inflammation-inflamm-aging. Given that the median age of cancer diagnosis is 66 years and that immunotherapeutic interventions such as cancer vaccines are currently given in combination with or after other forms of treatments which themselves have immune-modulating potential such as surgery, chemotherapy and radiotherapy, the choice of adjuvants requires careful consideration in order to achieve the maximum immune response in a compromised environment. In addition, more clinical trials need to be performed to carefully assess how less conventional form of immune adjuvants, such as exercise, diet and psychological care which have all be shown to influence immune responses can be incorporated to improve the efficacy of cancer vaccines. In this review, adjuvants will be discussed with respect to the above-mentioned important elements.},
	doi = {10.3389/fimmu.2020.615240},
	pmid = {33679703 [Indexed for MEDLINE]},
	note = {PMC7927599}
}

@ARTICLE{10.1016/j.ejpb.2020.12.004,
	author = {Dos Santos AM and Meneguin AB and Akhter DT and Fletcher N and Houston ZH and Bell C and Thurecht KJ, Gremião MPD},
	title = {Understanding the role of colon-specific microparticles based on retrograded starch/pectin in the delivery of chitosan nanoparticles along the gastrointestinal tract.},
	journal = {Eur J Pharm Biopharm},
	year = {2021},
	abstract = {The encapsulation of nanoparticles within microparticles designed for specific delivery to the colon is a relevant strategy to avoid premature degradation or release of nanoparticles during their passage through the stomach and upper gastrointestinal tract (GIT), allowing the targeted delivery of chemotherapeutics to the colon after oral administration. Here, we designed an oral multiparticulate system to achieve targeted release in the colon. In this sense, chitosan nanoparticles (CS NPs) encapsulated with 5-fluorouracil (5-FU) and incorporated into retrograded starch and pectin (RS/P) microparticles were developed and their in vivo distribution along the mouse GIT after oral administration was monitored using multispectral optical imaging. In vitro release studies revealed that the encapsulation of CS NPs into RS/P microparticles promoted greater control of 5-FU release rates, with a significant reduction (53%) in acid media that might replicate that found in the stomach following oral administration. The evaluation of the in vivo biodistribution of the CS NPs in mice showed a faster clearance in the distribution pattern along the mouse GIT, i.e., a shorter transit time of CS NPs compared to CS NPs-loaded RS/P microparticles. Additionally, CS NPs alone showed non-specific absorption into the blood-stream with associated kidney accumulation, while for the CS NPs-loaded RS/P microparticles no significant accumulation was observed in blood or major clearance organs. This suggests the specific degradability of RS/P by the colon microbiota appears to have been decisive in the higher protection of the CS NPs along the GIT until release in the colon, preventing unwanted absorption into the bloodstream and major organs following oral administration. Our findings represent a proof of concept for the use of RS/P microparticles as potential carriers for delivering drug-loaded nanoparticles to the colon and this work will contribute to the development of oral-systems for colorectal cancer therapy.},
	doi = {10.1016/j.ejpb.2020.12.004},
	pmid = {33309846 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/10408398.2020.1829541,
	author = {Farha AK and Gan RY and Li HB and Wu DT and Atanasov AG and Gul K and Zhang JR and Yang QQ and Corke H},
	title = {The anticancer potential of the dietary polyphenol rutin: Current status, challenges, and perspectives.},
	journal = {Crit Rev Food Sci Nutr},
	year = {2022},
	abstract = {Rutin is one of the most common dietary polyphenols found in vegetables, fruits, and other plants. It is metabolized by the mammalian gut microbiota and absorbed from the intestines, and becomes bioavailable in the form of conjugated metabolites. Rutin exhibits a plethora of bioactive properties, making it an extremely promising phytochemical. Numerous studies demonstrate that rutin can act as a chemotherapeutic and chemopreventive agent, and its anticancer effects can be mediated through the suppression of cell proliferation, the induction of apoptosis or autophagy, and the hindering of angiogenesis and metastasis. Rutin has been found to modulate multiple molecular targets involved in carcinogenesis, such as cell cycle mediators, cellular kinases, inflammatory cytokines, transcription factors, drug transporters, and reactive oxygen species. This review summarizes the natural sources of rutin, its bioavailability, and in particular its potential use as an anticancer agent, with highlighting its anticancer mechanisms as well as molecular targets. Additionally, this review updates the anticancer potential of its analogs, nanoformulations, and metabolites, and discusses relevant safety issues. Overall, rutin is a promising natural dietary compound with promising anticancer potential and can be widely used in functional foods, dietary supplements, and pharmaceuticals for the prevention and management of cancer.},
	doi = {10.1080/10408398.2020.1829541},
	pmid = {33054344 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ijbiomac.2020.09.214,
	author = {Shah BM and Palakurthi SS and Khare T and Khare S and Palakurthi S},
	title = {Natural proteins and polysaccharides in the development of micro/nano delivery systems for the treatment of inflammatory bowel disease.},
	journal = {Int J Biol Macromol},
	year = {2020},
	abstract = {Treatments for inflammatory bowel disease (IBD) are typically immunosuppressive. Despite a range of treatment options, limited efficacy, systemic toxicities like bone marrow suppression, infections and malignancy are their serious setbacks. There exists an unmet medical need for novel therapeutic agents without safety concerns resulting from chronic, systemic immunosuppression. Of late, several natural agents with better therapeutic potential have been reported. It is very likely that restricting the release of the active molecules to the intestine would further improve their clinical efficacy and safety. To this end, novel polymer-based micro/nano formulations protect the drug from gastric environment and slowly release the drug in the colon. However, cost and side-effects associated to synthetic polymers have led to the development of biocompatible, economic and pharmaceutically well-accepted biomacromolecules in exploring their potential in IBD. Since last few years, biological proteins, polysaccharides and their combinations have shown great efficacy in colitis induced animal models. In this review, micro/nano formulations developed using biomacromolecules like chitosan, zein, pectin, casein, alginate, dextran, glucomannan and hyaluronic acid have been reviewed focusing on their potential in protecting active cargo, avoiding premature release, distal colon targeting along with their impact on reshaping the altered gut microbiota and how it can ameliorate the colitis conditions.},
	doi = {10.1016/j.ijbiomac.2020.09.214},
	pmid = {33010274 [Indexed for MEDLINE]}
}

@ARTICLE{10.2174/1567201817666200527133719,
	author = {Chadha S and Kumar A and Srivastava SA and Behl T and Ranjan R},
	title = {Inulin as a Delivery Vehicle for Targeting Colon-Specific Cancer.},
	journal = {Curr Drug Deliv},
	year = {2020},
	abstract = {Natural polysaccharides, as well as biopolymers, are now days widely developed for targeting colon cancer using various drug delivery systems. Currently, healing conformations are being explored that can efficiently play a multipurpose role. Owing to the capability of extravagance colonic diseases with the least adverse effects, biopolymers for site specific colon delivery have developed an increased curiosity over the past decades. Inulin (INU) was explored for its probable application as an entrapment material concerning its degradation by enzymes in the colonic microflora and its drug release behavior in a sustained and controlled manner. INU is a polysaccharide and it consists of 2 to 1 linkage having an extensive array of beneficial uses such as a carrier for delivery of therapeutic agents as an indicative/investigative utensil or as a dietary fiber with added well-being aids. In the main, limited research, as well as information, is available on the delivery of therapeutic agents using inulin specifically for colon cancer because of its capability to subsist in the stomach's acidic medium. This exceptional steadiness and robustness properties are exploited in numerous patterns to target drugs securely for the management of colonic cancer, where they effectively act and kills colonic tumor cells easily. In this review article, recent efforts and inulin-based nano-technological approaches for colon cancer targeting are presented and discussed.},
	doi = {10.2174/1567201817666200527133719},
	pmid = {32459607 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/microorganisms8020199,
	author = {Reddy VP and Aryal P and Robinson S and Rafiu R and Obrenovich M and Perry G},
	title = {Polyphenols in Alzheimer's Disease and in the Gut-Brain Axis.},
	journal = {Microorganisms},
	year = {2020},
	abstract = {Polyphenolic antioxidants, including dietary plant lignans, modulate the gut-brain axis, which involves transformation of these polyphenolic compounds into physiologically active and neuroprotector compounds (called human lignans) through gut bacterial metabolism. These gut bacterial metabolites exert their neuroprotective effects in various neurodegenerative diseases, such as Alzheimer's disease (AD) and Parkinson's disease (PD), and also have protective effects against other diseases, such as cardiovascular diseases, cancer, and diabetes. For example, enterolactone and enterodiol, the therapeutically relevant polyphenols, are formed as the secondary gut bacterial metabolites of lignans, the non-flavonoid polyphenolic compounds found in plant-based foods. These compounds are also acetylcholinesterase inhibitors, and thereby have potential applications as therapeutics in AD and other neurological diseases. Polyphenols are also advanced glycation end product (AGE) inhibitors (antiglycating agents), and thereby exert neuroprotective effects in cases of AD. Thus, gut bacterial metabolism of lignans and other dietary polyphenolic compounds results in the formation of neuroprotective polyphenols-some of which have enhanced blood-brain barrier permeability. It is hypothesized that gut bacterial metabolism-derived polyphenols, when combined with the nanoparticle-based blood-brain barrier (BBB)-targeted drug delivery, may prove to be effective therapeutics for various neurological disorders, including traumatic brain injury (TBI), AD, and PD. This mini-review addresses the role of polyphenolic compounds in the gut-brain axis, focusing on AD.},
	doi = {10.3390/microorganisms8020199},
	pmid = {32023969},
	note = {PMC7074796}
}

@ARTICLE{10.3390/nu11051026,
	author = {Chen J and Zhao KN and Vitetta L},
	title = {Effects of Intestinal Microbial−Elaborated Butyrate on Oncogenic Signaling Pathways.},
	journal = {Nutrients},
	year = {2019},
	abstract = {The intestinal microbiota is well known to have multiple benefits on human health, including cancer prevention and treatment. The effects are partially mediated by microbiota-produced short chain fatty acids (SCFAs) such as butyrate, propionate and acetate. The anti-cancer effect of butyrate has been demonstrated in cancer cell cultures and animal models of cancer. Butyrate, as a signaling molecule, has effects on multiple signaling pathways. The most studied effect is its inhibition on histone deacetylase (HDAC), which leads to alterations of several important oncogenic signaling pathways such as JAK2/STAT3, VEGF. Butyrate can interfere with both mitochondrial apoptotic and extrinsic apoptotic pathways. In addition, butyrate also reduces gut inflammation by promoting T-regulatory cell differentiation with decreased activities of the NF-κB and STAT3 pathways. Through PKC and Wnt pathways, butyrate increases cancer cell differentiation. Furthermore, butyrate regulates oncogenic signaling molecules through microRNAs and methylation. Therefore, butyrate has the potential to be incorporated into cancer prevention and treatment regimens. In this review we summarize recent progress in butyrate research and discuss the future development of butyrate as an anti-cancer agent with emphasis on its effects on oncogenic signaling pathways. The low bioavailability of butyrate is a problem, which precludes clinical application. The disadvantage of butyrate for medicinal applications may be overcome by several approaches including nano-delivery, analogue development and combination use with other anti-cancer agents or phytochemicals.},
	doi = {10.3390/nu11051026},
	pmid = {31067776 [Indexed for MEDLINE]},
	note = {PMC6566851}
}

@ARTICLE{10.1039/c8fo02295j,
	author = {Rome S},
	title = {Biological properties of plant-derived extracellular vesicles.},
	journal = {Food Funct},
	year = {2019},
	abstract = {Identification of active constituents of our diet is crucial to understand the impact of food on health, and disease development, and for the formulation of functional food and nutraceuticals. Until now research into the pharmacological properties of the components of our diet has focused on vitamins, sterols, polyphenols, fiber, etc. But very recently, it has been found that plants contain various types of vesicles which are in contact with the intestinal tract throughout our lives. They participate in intestinal tissue renewal processes and modulate gut microbiota in healthy subjects and have important biological functions against inflammatory diseases (e.g.; colitis injury, liver steatosis) or cancers associated with their specific lipid and miRNA content. In addition, recent data have suggested that plant-derived nanovesicles would be excellent candidates for the delivery of therapeutic agents (e.g.; anti-cancerous drugs, siRNAs) or poorly soluble natural compounds (e.g.; curcumin), as they are able to cross mammalian barriers without inducing either an inflammatory response or necrosis, conversely to conventional liposomes. It is thus important to consider these plant-derived vesicles as new components of our food in order to evaluate their potential for health benefit and food-derived technology.},
	doi = {10.1039/c8fo02295j},
	pmid = {30724295 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/10408398.2016.1231168,
	author = {Gan RY and Li HB and Sui ZQ and Corke H},
	title = {Absorption, metabolism, anti-cancer effect and molecular targets of epigallocatechin gallate (EGCG): An updated review.},
	journal = {Crit Rev Food Sci Nutr},
	year = {2018},
	abstract = {Green tea is one of the most popular beverages in the world, especially in Asian countries. Consumption of green tea has been demonstrated to possess many health benefits, which mainly attributed to the main bioactive compound epigallocatechin gallate (EGCG), a flavone-3-ol polyphenol, in green tea. EGCG is mainly absorbed in the intestine, and gut microbiota play a critical role in its metabolism prior to absorption. EGCG exhibits versatile bioactivities, with its anti-cancer effect most attracting due to the cancer preventive effect of green tea consumption, and a great number of studies intensively investigated its anti-cancer effect. In this review, we therefore, first stated the absorption and metabolism process of EGCG, and then summarized its anti-cancer effect in vitro and in vivo, including its manifold anti-cancer actions and mechanisms, especially its anti-cancer stem cell effect, and next highlighted its various molecular targets involved in cancer inhibition. Finally, the anti-cancer effect of EGCG analogs and nanoparticles, as well as the potential cancer promoting effect of EGCG were also discussed. Understanding of the absorption, metabolism, anti-cancer effect and molecular targets of EGCG can be of importance to better utilize it as a chemopreventive and chemotherapeutic agent.},
	doi = {10.1080/10408398.2016.1231168},
	pmid = {27645804 [Indexed for MEDLINE]}
}
